import sailpoint.object.Application;
import sailpoint.object.Identity;
import sailpoint.object.Link;
import sailpoint.tools.Util;
import org.apache.commons.logging.Log;
import org.apache.commons.logging.LogFactory;

Log logger = LogFactory.getLog("Ascension.Rule.IdentitySelector.PresenceHealth");
  
logger.debug("Entering Ascension-Rule-IdentitySelector-PresenceHealth");
  
boolean flag = false;
boolean adLink = false;
boolean authLink = false;
List links = identity.getLinks();
if(!Util.isEmpty(links) && !identity.isInactive()){
	for(Link link : links){
		if(link !=null && !link.isDisabled() && link.getApplication() !=null){
			if(Util.nullSafeCaseInsensitiveEq(link.getApplication().getName(),"AD-AMITA")){
				adLink = true;
			}
			if(link.getApplication().isAuthoritative()){
				authLink = true;
			}
			if(adLink){
				flag = true;
				break;
			}
		}
	}
}
logger.debug("Existing Ascension-Rule-IdentitySelector-PresenceHealth");
return flag;
